struct Node {
    int val; 
    Node *left;
    Node *right;

    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
}; */

class Solution {
    void traverse(Node* root, vector<vector<int>>&paths, vector<int> path, int s, int cur){
        if(root == NULL)
          return;
        path.push_back(root->val);
        cur += root->val;
        if(!root->left && !root->right) {
            if(cur == s){
                paths.push_back(path);

            }
            return;
        }
        traverse(root->left, paths, path, s, cur);
        traverse(root->right, paths, path, s, cur);
        cur -= root->val;
        path.pop_back();
    }
  public:
    void targetSumPaths(Node* root, int target) {
        vector<int> path;
        vector<vector<int>> paths;
        traverse(root, paths, path, target, 0);

        for(auto &path: paths){
            for(int node: path){
                cout << node << " ";
            }
            cout << endl;
        }
    }
};

