class Solution {
    private void traverse(Node root, List<List<Integer>> paths, List<Integer> path, int target, int currentSum) {
        if (root == null) return;

        path.add(root.val);
        currentSum += root.val;

        if (root.left == null && root.right == null) {
            if (currentSum == target) {
                paths.add(new ArrayList<>(path));
            }
        } else {
            traverse(root.left, paths, path, target, currentSum);
            traverse(root.right, paths, path, target, currentSum);
        }

        path.remove(path.size() - 1);
    }

    public void targetSumPaths(Node root, int target) {
        List<List<Integer>> paths = new ArrayList<>();
        List<Integer> path = new ArrayList<>();
        traverse(root, paths, path, target, 0);

        for (List<Integer> p : paths) {
            for (int node : p) {
                System.out.print(node + " ");
            }
            System.out.println();
        }
    }
}

