class Solution {
    traverse(root, paths, path, target, cur) {
        if (!root) return;

        path.push(root.val);
        cur += root.val;

        if (!root.left && !root.right) {
            if (cur === target) {
                paths.push([...path]); // Push a copy of path to paths
            }
            path.pop(); // Backtrack
            return;
        }

        this.traverse(root.left, paths, path, target, cur);
        this.traverse(root.right, paths, path, target, cur);

        path.pop(); // Backtrack
    }

    targetSumPaths(root, target) {
        const paths = [];
        const path = [];
        this.traverse(root, paths, path, target, 0);

        for (let path of paths) {
            console.log(path.join(' '));
        }
    }
}
